class Solution:
    def isHappy(self, n):
        def digit_sq(x):
            s = 0
            while x:
                x, d = divmod(x, 10)
                s += d * d
            return s
        seen = set()
        while n != 1 and n not in seen:
            seen.add(n)
            n = digit_sq(n)
        return n == 1

