class Solution:
    def isHappy(self, n):
        def digit_sq(x):
            s = 0
            while x:
                x, d = divmod(x, 10)
                s += d * d
            return s
        slow, fast = n, digit_sq(n)
        while fast != 1 and slow != fast:
            slow = digit_sq(slow)
            fast = digit_sq(digit_sq(fast))
        return fast == 1

