var isHappy = function(n) {
    function digitSq(x) {
        let s = 0;
        while (x > 0) {
            const d = x % 10;
            s += d * d;
            x = Math.floor(x / 10);
        }
        return s;
    }
    let slow = n, fast = digitSq(n);
    while (fast !== 1 && slow !== fast) {
        slow = digitSq(slow);
        fast = digitSq(digitSq(fast));
    }
    return fast === 1;
};
